    45→// CreateOrUpdateMR creates or updates a GitLab merge request
    46→func (g *GitLabProvider) CreateOrUpdateMR(ctx context.Context, config MRConfig) (*MRResult, error) {
    47→	if err := g.ValidateConfiguration(); err != nil {
    48→		return nil, fmt.Errorf("configuration validation failed: %w", err)
    49→	}
    50→
    51→	// Extract GitLab project from repository URL
    52→	project, err := extractGitLabProject(config.RepoURL)
    53→	if err != nil {
    54→		return nil, fmt.Errorf("failed to extract GitLab project from URL %s: %w", config.RepoURL, err)
    55→	}
    56→
    57→	// Check for existing MR with same source branch
    58→	existingMR, err := g.findExistingMR(ctx, project, config.SourceBranch)
    59→	if err != nil {
    60→		return nil, fmt.Errorf("failed to check for existing MR: %w", err)
    61→	}
    62→
    63→	if existingMR != nil {
    64→		// Update existing MR
    65→		result, err := g.updateMR(ctx, project, existingMR.IID, config)
    66→		if err != nil {
    67→			return nil, fmt.Errorf("failed to update existing MR: %w", err)
    68→		}
    69→		result.Created = false
    70→		return result, nil
    71→	}
    72→
    73→	// Create new MR
    74→	result, err := g.createMR(ctx, project, config)
    75→	if err != nil {
    76→		return nil, fmt.Errorf("failed to create new MR: %w", err)
    77→	}
    78→	result.Created = true
    79→	return result, nil
    80→}
