   119→// createMR creates a new GitLab merge request
   120→func (g *GitLabProvider) createMR(ctx context.Context, project string, config MRConfig) (*MRResult, error) {
   121→	// Prepare target branch (strip refs/heads/ prefix if present)
   122→	targetBranch := strings.TrimPrefix(config.TargetBranch, "refs/heads/")
   123→
   124→	mrRequest := gitLabMRRequest{
   125→		Title:        config.Title,
   126→		Description:  config.Description,
   127→		SourceBranch: config.SourceBranch,
   128→		TargetBranch: targetBranch,
   129→		Labels:       strings.Join(config.Labels, ","),
   130→	}
   131→
   132→	body, err := json.Marshal(mrRequest)
   133→	if err != nil {
   134→		return nil, fmt.Errorf("failed to marshal request: %w", err)
   135→	}
   136→
   137→	encodedProject := url.PathEscape(project)
   138→	apiURL := fmt.Sprintf("%s/api/v4/projects/%s/merge_requests", g.baseURL, encodedProject)
   139→
   140→	req, err := http.NewRequestWithContext(ctx, "POST", apiURL, bytes.NewBuffer(body))
   141→	if err != nil {
   142→		return nil, fmt.Errorf("failed to create request: %w", err)
   143→	}
   144→
   145→	req.Header.Set("Authorization", "Bearer "+g.token)
   146→	req.Header.Set("Content-Type", "application/json")
   147→
   148→	resp, err := g.client.Do(req)
   149→	if err != nil {
   150→		return nil, fmt.Errorf("failed to make API request: %w", err)
   151→	}
   152→	defer resp.Body.Close()
   153→
   154→	if resp.StatusCode != http.StatusCreated {
   155→		return nil, fmt.Errorf("GitLab API error: status %d", resp.StatusCode)
   156→	}
   157→
   158→	var mrResponse gitLabMRResponse
   159→	if err := json.NewDecoder(resp.Body).Decode(&mrResponse); err != nil {
   160→		return nil, fmt.Errorf("failed to decode response: %w", err)
   161→	}
   162→
   163→	return &MRResult{
   164→		MRURL: mrResponse.WebURL,
   165→		MRID:  mrResponse.IID,
   166→	}, nil
   167→}
