    12→// ValidateUnifiedDiff runs a dry-run git apply --check on the diff file in the repo path
    13→func ValidateUnifiedDiff(ctx context.Context, repoPath, diffPath string) error {
    14→    cmd := exec.CommandContext(ctx, "git", "apply", "--check", diffPath)
    15→    cmd.Dir = repoPath
    16→    out, err := cmd.CombinedOutput()
    17→    if err != nil {
    18→        return fmt.Errorf("git apply --check failed: %v: %s", err, string(out))
    19→    }
    20→    return nil
    21→}
