    23→// ApplyUnifiedDiff applies a unified diff to the repo path
    24→func ApplyUnifiedDiff(ctx context.Context, repoPath, diffPath string) error {
    25→    cmd := exec.CommandContext(ctx, "git", "apply", diffPath)
    26→    cmd.Dir = repoPath
    27→    out, err := cmd.CombinedOutput()
    28→    if err != nil {
    29→        return fmt.Errorf("git apply failed: %v: %s", err, string(out))
    30→    }
    31→    return nil
    32→}
