    34→// ValidateDiffPaths checks that all changed file paths in the unified diff match at least one allowed glob.
    35→// allowedGlobs example: []string{"src/**", "pom.xml"}
    36→func ValidateDiffPaths(diffPath string, allowedGlobs []string) error {
    37→    f, err := os.Open(diffPath)
    38→    if err != nil { return err }
    39→    defer f.Close()
    40→    scanner := bufio.NewScanner(f)
    41→    for scanner.Scan() {
    42→        line := scanner.Text()
    43→        // Look for lines starting with "+++ " and extract path portion
    44→        if len(line) > 4 && line[:4] == "+++ " {
    45→            // Expected format: +++ b/path or +++ /dev/null
    46→            fields := line[4:]
    47→            if fields == "/dev/null" { continue }
    48→            // Strip leading prefixes like a/ or b/
    49→            p := fields
    50→            if len(p) > 2 && (p[:2] == "a/" || p[:2] == "b/") { p = p[2:] }
    51→            // Match against allowed globs
    52→            ok := false
    53→            for _, pat := range allowedGlobs {
    54→                if m, _ := filepath.Match(pat, p); m {
    55→                    ok = true
    56→                    break
    57→                }
    58→            }
    59→            if !ok {
    60→                return fmt.Errorf("diff touches disallowed path: %s", p)
